-- 一键重置并导入当前项目题库到 system 库（DS/OS/CN/CO）
CREATE DATABASE IF NOT EXISTS `system` DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `system`;
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

CREATE TABLE IF NOT EXISTS `sys_user` (
  `id` int PRIMARY KEY AUTO_INCREMENT,
  `username` varchar(50) NOT NULL,
  `password` varchar(100) NOT NULL,
  `name` varchar(100),
  `avatar` varchar(255),
  `role` varchar(20) NOT NULL,
  `subject` varchar(20) NOT NULL,
  `status` tinyint DEFAULT 1,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  UNIQUE KEY `uk_user_identity` (`username`,`role`,`subject`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS `exercise` (
  `id` varchar(64) PRIMARY KEY,
  `subject` varchar(20) NOT NULL,
  `chapter` varchar(100) NOT NULL,
  `chapter_slug` varchar(100),
  `stem` text NOT NULL,
  `option_a` varchar(255),
  `option_b` varchar(255),
  `option_c` varchar(255),
  `option_d` varchar(255),
  `answer` varchar(4) NOT NULL,
  `analysis` text,
  `difficulty` int DEFAULT 2,
  `knowledge_points` text,
  `attachment_url` varchar(255),
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  KEY `idx_exercise_subject` (`subject`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS `user_answer` (
  `id` bigint PRIMARY KEY AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `subject` varchar(20) NOT NULL,
  `exercise_id` varchar(64) NOT NULL,
  `is_correct` tinyint NOT NULL,
  `chosen_option` varchar(4),
  `correct_answer` varchar(4),
  `answered_at` datetime,
  KEY `idx_answer_user_subject` (`user_id`,`subject`),
  KEY `idx_answer_exercise` (`exercise_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


CREATE TABLE IF NOT EXISTS `knowledge_relation` (
  `id` bigint PRIMARY KEY AUTO_INCREMENT,
  `subject` varchar(20) NOT NULL,
  `source_kp` varchar(100) NOT NULL,
  `target_kp` varchar(100) NOT NULL,
  `relation_type` varchar(32) DEFAULT 'related',
  `weight` decimal(6,2) DEFAULT 1.00,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  KEY `idx_kg_subject_source` (`subject`,`source_kp`),
  KEY `idx_kg_subject_target` (`subject`,`target_kp`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- 重置业务数据
TRUNCATE TABLE `user_answer`;
TRUNCATE TABLE `knowledge_relation`;
TRUNCATE TABLE `exercise`;
DELETE FROM `sys_user` WHERE `subject` IN ('DS','OS','CN','CO');

-- 初始化管理员账号：admin/admin（BCrypt）

-- 导入 DS 题库，共 453 题

-- 导入 OS 题库，共 572 题

-- 导入 CN 题库，共 512 题

-- 导入 CO 题库，共 544 题

SET FOREIGN_KEY_CHECKS = 1;
SELECT subject, COUNT(*) AS total FROM exercise WHERE subject IN ('DS','OS','CN','CO') GROUP BY subject ORDER BY subject;